package com.example.ruleengine.service;

import com.example.ruleengine.domain.Rule;
import com.example.ruleengine.repository.RuleRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Component;

/**
 * 规则使用检查器
 * 用于检查规则是否在使用中
 *
 * TODO: 在 Phase 5 实现灰度发布后，检查是否有灰度配置
 * TODO: 在 Phase 6 实现依赖分析后，检查是否有其他规则依赖
 */
@Component
@RequiredArgsConstructor
@Slf4j
public class RuleUsageChecker {

    private final RuleRepository ruleRepository;

    /**
     * 检查规则是否在使用中
     *
     * 当前实现：检查规则是否处于 ACTIVE 状态且已启用
     * 后续增强：
     * - 检查是否有灰度配置引用此规则
     * - 检查是否有其他规则依赖此规则
     * - 检查是否有正在执行的规则实例
     *
     * @param ruleKey 规则Key
     * @return true 如果规则正在使用中，false 否则
     */
    public boolean isRuleInUse(String ruleKey) {
        try {
            Rule rule = ruleRepository.findByRuleKey(ruleKey).orElse(null);

            if (rule == null) {
                log.debug("规则不存在: ruleKey={}", ruleKey);
                return false;
            }

            // 检查规则是否处于 ACTIVE 状态且已启用
            boolean inUse = rule.getEnabled() && rule.getStatus() == com.example.ruleengine.constants.RuleStatus.ACTIVE;

            if (inUse) {
                log.debug("规则正在使用中: ruleKey={}, status={}, enabled={}",
                        ruleKey, rule.getStatus(), rule.getEnabled());
            }

            return inUse;

        } catch (Exception e) {
            log.error("检查规则使用状态失败: ruleKey={}", ruleKey, e);
            return false;
        }
    }

    /**
     * 检查规则是否可以安全删除
     *
     * @param ruleKey 规则Key
     * @return true 如果规则可以安全删除，false 否则
     */
    public boolean canSafelyDelete(String ruleKey) {
        // 如果规则正在使用中，不能删除
        if (isRuleInUse(ruleKey)) {
            log.warn("规则正在使用中，不能删除: ruleKey={}", ruleKey);
            return false;
        }

        // TODO: 后续增强
        // - 检查是否有灰度配置引用此规则
        // - 检查是否有其他规则依赖此规则

        return true;
    }

    /**
     * 获取规则使用详情
     *
     * @param ruleKey 规则Key
     * @return 使用详情描述
     */
    public String getUsageDetails(String ruleKey) {
        Rule rule = ruleRepository.findByRuleKey(ruleKey).orElse(null);

        if (rule == null) {
            return "规则不存在";
        }

        StringBuilder details = new StringBuilder();
        details.append("规则Key: ").append(ruleKey).append("\n");
        details.append("状态: ").append(rule.getStatus().getDescription()).append("\n");
        details.append("启用: ").append(rule.getEnabled() ? "是" : "否").append("\n");
        details.append("版本: ").append(rule.getVersion()).append("\n");
        details.append("创建人: ").append(rule.getCreatedBy()).append("\n");

        if (isRuleInUse(ruleKey)) {
            details.append("使用状态: 正在使用中\n");
        } else {
            details.append("使用状态: 未使用\n");
        }

        return details.toString();
    }
}

