package com.example.ruleengine.controller;

import com.example.ruleengine.constants.RuleStatus;
import com.example.ruleengine.domain.Rule;
import com.example.ruleengine.model.dto.CreateRuleRequest;
import com.example.ruleengine.model.dto.RuleQuery;
import com.example.ruleengine.model.dto.UpdateRuleRequest;
import com.example.ruleengine.model.dto.ValidateScriptRequest;
import com.example.ruleengine.model.dto.ValidateScriptResponse;
import com.example.ruleengine.service.RuleUsageChecker;
import com.example.ruleengine.service.lifecycle.RuleLifecycleService;
import com.example.ruleengine.validator.GroovyScriptValidator;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.util.Arrays;
import java.util.Optional;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * RuleController 集成测试
 * 测试完整的规则生命周期 API
 */
@WebMvcTest(RuleController.class)
class RuleControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private RuleLifecycleService ruleLifecycleService;

    @MockBean
    private GroovyScriptValidator scriptValidator;

    @MockBean
    private RuleUsageChecker ruleUsageChecker;

    private Rule testRule;
    private CreateRuleRequest createRequest;
    private UpdateRuleRequest updateRequest;

    @BeforeEach
    void setUp() {
        // 初始化测试规则
        testRule = Rule.builder()
                .id(1L)
                .ruleKey("test_rule")
                .ruleName("测试规则")
                .ruleDescription("测试规则描述")
                .groovyScript("return true")
                .version(1)
                .status(RuleStatus.DRAFT)
                .createdBy("test_user")
                .enabled(true)
                .build();

        // 初始化创建请求
        createRequest = CreateRuleRequest.builder()
                .ruleKey("test_rule")
                .ruleName("测试规则")
                .ruleDescription("测试规则描述")
                .groovyScript("return true")
                .build();

        // 初始化更新请求
        updateRequest = UpdateRuleRequest.builder()
                .ruleName("更新后的规则名称")
                .groovyScript("return false")
                .changeReason("更新脚本")
                .build();
    }

    @Test
    void testCreateRule_Success() throws Exception {
        // Given
        when(ruleLifecycleService.createRule(any(CreateRuleRequest.class), anyString()))
                .thenReturn(testRule);

        // When & Then
        mockMvc.perform(post("/api/v1/rules")
                        .header("X-Operator", "test_user")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(createRequest)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.ruleKey").value("test_rule"))
                .andExpect(jsonPath("$.ruleName").value("测试规则"))
                .andExpect(jsonPath("$.status").value("DRAFT"))
                .andExpect(jsonPath("$.version").value(1));
    }

    @Test
    void testUpdateRule_Success() throws Exception {
        // Given
        Rule updatedRule = Rule.builder()
                .id(1L)
                .ruleKey("test_rule")
                .ruleName("更新后的规则名称")
                .groovyScript("return false")
                .version(2)
                .status(RuleStatus.DRAFT)
                .build();

        when(ruleLifecycleService.updateRule(anyString(), any(UpdateRuleRequest.class), anyString()))
                .thenReturn(updatedRule);

        // When & Then
        mockMvc.perform(put("/api/v1/rules/test_rule")
                        .header("X-Operator", "test_user")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(updateRequest)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.ruleKey").value("test_rule"))
                .andExpect(jsonPath("$.ruleName").value("更新后的规则名称"))
                .andExpect(jsonPath("$.version").value(2));
    }

    @Test
    void testDeleteRule_Success() throws Exception {
        // Given
        when(ruleUsageChecker.canSafelyDelete(anyString())).thenReturn(true);

        // When & Then
        mockMvc.perform(delete("/api/v1/rules/test_rule")
                        .header("X-Operator", "test_user"))
                .andExpect(status().isOk());
    }

    @Test
    void testEnableRule_Success() throws Exception {
        // Given
        Rule activeRule = Rule.builder()
                .id(1L)
                .ruleKey("test_rule")
                .ruleName("测试规则")
                .status(RuleStatus.ACTIVE)
                .enabled(true)
                .build();

        when(ruleLifecycleService.enableRule(anyString(), anyString()))
                .thenReturn(activeRule);

        // When & Then
        mockMvc.perform(post("/api/v1/rules/test_rule/enable")
                        .header("X-Operator", "test_user"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.status").value("ACTIVE"))
                .andExpect(jsonPath("$.enabled").value(true));
    }

    @Test
    void testDisableRule_Success() throws Exception {
        // Given
        Rule disabledRule = Rule.builder()
                .id(1L)
                .ruleKey("test_rule")
                .ruleName("测试规则")
                .status(RuleStatus.DRAFT)
                .enabled(false)
                .build();

        when(ruleLifecycleService.disableRule(anyString(), anyString()))
                .thenReturn(disabledRule);

        // When & Then
        mockMvc.perform(post("/api/v1/rules/test_rule/disable")
                        .header("X-Operator", "test_user"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.enabled").value(false));
    }

    @Test
    void testGetRule_Success() throws Exception {
        // Given
        when(ruleLifecycleService.getRule(anyString()))
                .thenReturn(testRule);

        // When & Then
        mockMvc.perform(get("/api/v1/rules/test_rule"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.ruleKey").value("test_rule"))
                .andExpect(jsonPath("$.ruleName").value("测试规则"));
    }

    @Test
    void testListRules_Success() throws Exception {
        // Given
        when(ruleLifecycleService.listRules(any()))
                .thenReturn(org.springframework.data.domain.Page.empty());

        // When & Then
        mockMvc.perform(get("/api/v1/rules")
                        .param("page", "0")
                        .param("size", "20"))
                .andExpect(status().isOk());
    }

    @Test
    void testValidateScript_Success() throws Exception {
        // Given
        ValidateScriptRequest request = ValidateScriptRequest.builder()
                .groovyScript("return true")
                .build();

        when(scriptValidator.validate(anyString()))
                .thenReturn(GroovyScriptValidator.ValidationResult.success());

        // When & Then
        mockMvc.perform(post("/api/v1/rules/validate")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.valid").value(true));
    }

    @Test
    void testValidateScript_Failure() throws Exception {
        // Given
        ValidateScriptRequest request = ValidateScriptRequest.builder()
                .groovyScript("invalid script")
                .build();

        when(scriptValidator.validate(anyString()))
                .thenReturn(GroovyScriptValidator.ValidationResult.error("语法错误"));

        // When & Then
        mockMvc.perform(post("/api/v1/rules/validate")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.valid").value(false))
                .andExpect(jsonPath("$.errorMessage").value("Groovy脚本语法错误"));
    }

    @Test
    void testQueryRules_Success() throws Exception {
        // Given
        RuleQuery query = RuleQuery.builder()
                .status(RuleStatus.DRAFT)
                .createdBy("test_user")
                .build();

        when(ruleLifecycleService.queryRules(any(RuleQuery.class), any()))
                .thenReturn(org.springframework.data.domain.Page.empty());

        // When & Then
        mockMvc.perform(post("/api/v1/rules/query")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(query))
                        .param("page", "0")
                        .param("size", "20"))
                .andExpect(status().isOk());
    }

    @Test
    void testCreateRule_ValidationError() throws Exception {
        // Given - 规则Key为空，应该触发验证错误
        CreateRuleRequest invalidRequest = CreateRuleRequest.builder()
                .ruleKey("")
                .ruleName("测试规则")
                .groovyScript("return true")
                .build();

        // When & Then
        mockMvc.perform(post("/api/v1/rules")
                        .header("X-Operator", "test_user")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(invalidRequest)))
                .andExpect(status().isBadRequest());
    }
}

