package com.example.ruleengine.validator;

import com.example.ruleengine.constants.RuleStatus;
import com.example.ruleengine.repository.RuleRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Component;

/**
 * 规则使用检查器
 * 用于检查规则是否正在使用中，防止误删除
 */
@Component
@RequiredArgsConstructor
@Slf4j
public class RuleUsageChecker {

    private final RuleRepository ruleRepository;

    /**
     * 检查规则是否可以安全删除
     * 当前简化实现：仅检查规则状态
     * 未来可以扩展为检查规则是否在决策队列中、是否有依赖关系等
     *
     * @param ruleKey 规则Key
     * @return true 可以安全删除，false 不能删除
     */
    public boolean canSafelyDelete(String ruleKey) {
        return ruleRepository.findByRuleKey(ruleKey)
                .map(rule -> {
                    // 只有 DRAFT 和 ARCHIVED 状态的规则可以删除
                    boolean canDelete = rule.getStatus() == RuleStatus.DRAFT
                            || rule.getStatus() == RuleStatus.ARCHIVED;

                    if (!canDelete) {
                        log.warn("规则正在使用中，不能删除: ruleKey={}, status={}",
                                ruleKey, rule.getStatus());
                    }

                    return canDelete;
                })
                .orElse(true); // 规则不存在，视为可以删除
    }
}

