     */
    @Bean("featureCache")
    public Cache<String, Object> featureCache() {
        return Caffeine.newBuilder()
                .maximumSize(10_000)
                .expireAfterWrite(30, TimeUnit.MINUTES)
                .recordStats()
                .build();
    }

    /**
     * 缓存管理器
